   313→                  onClick={() => setBatchDeleteOpen(true)}
   314→                  className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors hover:opacity-90"
   315→                  style={{
   316→                    backgroundColor: "#dc2626",
   317→                    color: "#ffffff",
   318→                    fontFamily: "var(--font-dm-sans)",
   319→                    fontSize: "13px",
   320→                    fontWeight: 500,
   321→                  }}
   322→                >
   323→                  <Trash2 className="h-3.5 w-3.5" />
   324→                  Delete Selected
   325→                </button>
   326→              </div>
   327→            )}
   328→          </>
   329→        )}
   330→      </div>
   331→
   332→      {/* Create dialog */}
   333→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   334→        <DialogContent className="sm:max-w-lg">
   335→          <DialogHeader>
   336→            <DialogTitle>Create Subscription</DialogTitle>
   337→          </DialogHeader>
   338→          <SubscriptionForm
   339→            title="Create Subscription"
   340→            onSubmit={async (input) => {
   341→              await subsApi.create(input);
   342→            }}
   343→            onBatchSubmit={async (input) => {
   344→              await subsApi.batchCreate(input);
   345→            }}
   346→            onSuccess={() => {
   347→              setCreateOpen(false);
   348→              mutate("subscriptions");
   349→              clearSelection();
   350→            }}
   351→            onCancel={() => setCreateOpen(false)}
   352→          />
   353→        </DialogContent>
   354→      </Dialog>
   355→
   356→      {/* Edit dialog */}
   357→      <Dialog
   358→        open={!!editingSub}
   359→        onOpenChange={(open) => {
   360→          if (!open) setEditingSub(null);
   361→        }}
   362→      >
   363→        <DialogContent className="sm:max-w-lg">
   364→          <DialogHeader>
   365→            <DialogTitle>Edit Subscription</DialogTitle>
   366→          </DialogHeader>
   367→          {editingSub && (
   368→            <SubscriptionForm
   369→              key={editingSub.id}
   370→              title="Edit Subscription"
   371→              initial={editingSub}
   372→              onSubmit={async (input) => {
   373→                await subsApi.update(editingSub.id, input);
   374→              }}
   375→              onSuccess={() => {
   376→                setEditingSub(null);
   377→                mutate("subscriptions");
   378→                clearSelection();
   379→              }}
   380→              onCancel={() => setEditingSub(null)}
   381→            />
   382→          )}
   383→        </DialogContent>
   384→      </Dialog>
   385→
   386→      {/* Delete dialog */}
   387→      <ConfirmDialog
   388→        open={!!deletingId}
   389→        onOpenChange={(open) => {
   390→          if (!open) setDeletingId(null);
   391→        }}
   392→        title="Delete Subscription"
   393→        description="This will permanently delete this subscription. This cannot be undone."
   394→        onConfirm={async () => {
   395→          if (deletingId) {
   396→            await subsApi.delete(deletingId);
   397→            mutate("subscriptions");
   398→            clearSelection();
   399→          }
   400→        }}
   401→      />
   402→
   403→      {/* Batch delete dialog */}
   404→      <ConfirmDialog
   405→        open={batchDeleteOpen}
   406→        onOpenChange={setBatchDeleteOpen}
   407→        title="Delete Subscriptions"
   408→        description={`This will permanently delete ${selectedIds.size} subscription${selectedIds.size === 1 ? "" : "s"}. This cannot be undone.`}
   409→        onConfirm={async () => {
   410→          await subsApi.batchDelete({ ids: [...selectedIds] });
   411→          mutate("subscriptions");
   412→          clearSelection();
   413→        }}
   414→      />
   415→    </div>
   416→  );
   417→}
